import { Component } from '@angular/core';

@Component({
  selector: 'app-criar-personagem',
  templateUrl: './criar-personagem.component.html',
  styleUrls: ['./criar-personagem.component.css']
})
export class CriarPersonagemComponent {
  etapa: number = 1;

  racas = [
    { nome: 'Humano', img: '' },
    { nome: 'Elfo', img: '' },
    { nome: 'Anão', img: '' },
    { nome: 'Halfling', img: '' },
    { nome: 'Gnomo', img: '' },
    { nome: 'Meio-Orc', img: '' },
    { nome: 'Meio-Elfo', img: '' },
    { nome: 'Draconato', img: '' },
    { nome: 'Tiefling', img: '' }
  ];

  classes = [
    { nome: 'Bárbaro', img: '' },
    { nome: 'Bardo', img: '' },
    { nome: 'Bruxo', img: '' },
    { nome: 'Clérigo', img: '' },
    { nome: 'Druida', img: '' },
    { nome: 'Feiticeiro', img: '' },
    { nome: 'Guerreiro', img: '' },
    { nome: 'Ladino', img: '' },
    { nome: 'Mago', img: '' },
    { nome: 'Monge', img: '' },
    { nome: 'Paladino', img: '' },
    { nome: 'Patrulheiro', img: '' }
  ];

  atributos: Record<string, number> = {
    forca: 10,
    destreza: 10,
    constituicao: 10,
    inteligencia: 10,
    sabedoria: 10,
    carisma: 10
  };

  personagem = {
    raca: '',
    classe: '',
    atributos: this.atributos
  };

  selecionarRaca(raca: string) {
    this.personagem.raca = raca;
    this.etapa = 2;
  }

  selecionarClasse(classe: string) {
    this.personagem.classe = classe;
    this.etapa = 3;
  }

  definirAtributo(atributo: string, valor: number) {
    this.personagem.atributos[atributo] = valor;
  }

  rolarAtributos() {
    for (let atributo in this.atributos) {
      this.atributos[atributo] = this.rolarDado(3, 6);
    }
  }

  rolarDado(quantidade: number, faces: number): number {
    let total = 0;
    for (let i = 0; i < quantidade; i++) {
      total += Math.floor(Math.random() * faces) + 1;
    }
    return total;
  }

  voltarEtapa() {
    if (this.etapa > 1) {
      this.etapa--;
    }
  }
}
<app-header></app-header>
<section>
    <div class="criacao-personagem">
        <!-- Etapa 1: Escolher Raça -->
        <div *ngIf="etapa === 1" class="etapa">
            <h2>Escolha sua Raça</h2>
            <div class="opcoes">
                <div *ngFor="let raca of racas" (click)="selecionarRaca(raca.nome)" class="opcao">
                    <img [src]="raca.img" [alt]="raca.nome">
                    <p>{{ raca.nome }}</p>
                </div>
            </div>
        </div>

        <!-- Etapa 2: Escolher Classe -->
        <div *ngIf="etapa === 2" class="etapa">
            <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
            <h2>Escolha sua Classe</h2>
            <div class="opcoes">
                <div *ngFor="let classe of classes" (click)="selecionarClasse(classe.nome)" class="opcao">
                    <img [src]="classe.img" [alt]="classe.nome">
                    <p>{{ classe.nome }}</p>
                </div>
            </div>
        </div>

        <!-- Etapa 3: Distribuir Atributos -->
        <div *ngIf="etapa === 3" class="etapa">
            <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
            <h2>Distribua seus Atributos</h2>
            <button (click)="rolarAtributos()" class="btn-rolar">Rolar Atributos</button>
            <div class="atributos">
                <div *ngFor="let atributo of atributos | keyvalue" class="atributo">
                    <span>{{ atributo.key | titlecase }}:</span>
                    <input type="number" [(ngModel)]="atributo.value">
                </div>
            </div>
            <button (click)="etapa = 4" class="btn-avancar">Avançar →</button>
        </div>

        <!-- Etapa 4: Resumo do Personagem -->
        <div *ngIf="etapa === 4" class="etapa">
            <button (click)="voltarEtapa()" class="btn-voltar">← Voltar</button>
            <h2>Resumo do Personagem</h2>
            <p><strong>Raça:</strong> {{ personagem.raca }}</p>
            <p><strong>Classe:</strong> {{ personagem.classe }}</p>
            <h3>Atributos:</h3>
            <ul>
                <li *ngFor="let atributo of personagem.atributos | keyvalue">
                    <strong>{{ atributo.key | titlecase }}:</strong> {{ atributo.value }}
                </li>
            </ul>
            <button class="btn-finalizar">Finalizar</button>
        </div>
    </div>
</section>
<app-footer></app-footer>
